// Fisher-Yates shuffle
function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Select 100 random questions: 20 per dimension, balanced polarity
export function selectTestQuestions(): Question[] {
  const dimensions: MBTIDimension[] = ["EI", "SN", "TF", "JP", "AT"];
  const selected: Question[] = [];

  for (const dim of dimensions) {
    const pool = QUESTION_BANK.filter(q => q.dimension === dim);
    const shuffled = shuffle(pool);
    selected.push(...shuffled.slice(0, 20));
  }

  return shuffle(selected);
}
